#include <bits/stdc++.h>
using namespace std;
const long long mod=1e9+7;
set<unsigned long long> ht;
int n;
int main(){
    cin>>n;
    for(int i=1;i<=n;i++){
    	unsigned long long a,h=0,w=0;
    	for(int j=1;j<=6;j++){
            cin>>a;
            h+=a*a,w+=a*a*a;
        }
        int tmp=ht.size();
        ht.insert(w*h);
        if(ht.size()==tmp){
            cout<<"Twin snowflakes found.";
            //如果set的大小与原来一样，说明前面已有相同的雪花
            return 0;
        }
    }
    cout<<"No two snowflakes are alike.";
    //否则没有出现相同的雪花
    return 0;
}
